 1→import { NextResponse } from 'next/server';
 2→import { createClient } from '@/lib/supabase/server';
 3→import { stripe, PLANS } from '@/lib/stripe';
 4→
 5→export async function POST(req: Request) {
 6→  const supabase = createClient();
 7→  const { data: { user } } = await supabase.auth.getUser();
 8→
 9→  if (!user) return NextResponse.json({ error: 'Unauthorized' }, { status: 401 });
10→
11→  const body = await req.json();
12→  const { workspaceId, plan } = body; 
13→
14→  if (!workspaceId) return NextResponse.json({ error: 'Workspace ID required' }, { status: 400 });
15→
16→  // 1. Vérifier le rôle (Owner/Admin seulement)
17→  const { data: membership } = await supabase
18→    .from('workspace_users')
19→    .select('role')
20→    .eq('workspace_id', workspaceId)
21→    .eq('user_id', user.id)
22→    .single();
23→
24→  if (!membership || !['owner', 'admin'].includes(membership.role)) {
25→    return NextResponse.json({ error: 'Forbidden' }, { status: 403 });
26→  }
27→
28→  // 2. Récupérer le customer ID existant s'il y en a un
29→  const { data: workspace } = await supabase
30→    .from('workspaces')
31→    .select('stripe_customer_id')
32→    .eq('id', workspaceId)
33→    .single();
34→
35→  let customerId = workspace?.stripe_customer_id;
36→
37→  // 3. Créer le Customer Stripe si inexistant
38→  if (!customerId) {
39→    const customer = await stripe.customers.create({
40→      email: user.email,
41→      metadata: { workspaceId: workspaceId }
42→    });
43→    customerId = customer.id;
44→    // Mise à jour DB
45→    await supabase.from('workspaces').update({ stripe_customer_id: customerId }).eq('id', workspaceId);
46→  }
47→
48→  // 4. Créer la session
49→  const priceId = PLANS[plan as keyof typeof PLANS];
50→  
51→  const session = await stripe.checkout.sessions.create({
52→    customer: customerId,
53→    line_items: [{ price: priceId, quantity: 1 }],
54→    mode: 'subscription',
55→    success_url: `${process.env.NEXT_PUBLIC_APP_URL}/app/settings/billing?success=true`,
56→    cancel_url: `${process.env.NEXT_PUBLIC_APP_URL}/app/settings/billing?canceled=true`,
57→    subscription_data: {
58→      metadata: { workspaceId: workspaceId }
59→    },
60→    metadata: { workspaceId: workspaceId }
61→  });
62→
63→  return NextResponse.json({ url: session.url });
64→}

