 1→import { createServerClient, type CookieOptions } from '@supabase/ssr'
 2→import { NextResponse, type NextRequest } from 'next/server'
 3→
 4→export async function updateSession(request: NextRequest) {
 5→  let response = NextResponse.next({
 6→    request: {
 7→      headers: request.headers,
 8→    },
 9→  })
10→
11→  const supabase = createServerClient(
12→    process.env.NEXT_PUBLIC_SUPABASE_URL!,
13→    process.env.NEXT_PUBLIC_SUPABASE_ANON_KEY!,
14→    {
15→      cookies: {
16→        get(name: string) {
17→          return request.cookies.get(name)?.value
18→        },
19→        set(name: string, value: string, options: CookieOptions) {
20→          request.cookies.set({
21→            name,
22→            value,
23→            ...options,
24→          })
25→          response = NextResponse.next({
26→            request: {
27→              headers: request.headers,
28→            },
29→          })
30→          response.cookies.set({
31→            name,
32→            value,
33→            ...options,
34→          })
35→        },
36→        remove(name: string, options: CookieOptions) {
37→          request.cookies.set({
38→            name,
39→            value: '',
40→            ...options,
41→          })
42→          response = NextResponse.next({
43→            request: {
44→              headers: request.headers,
45→            },
46→          })
47→          response.cookies.set({
48→            name,
49→            value: '',
50→            ...options,
51→          })
52→        },
53→      },
54→    }
55→  )
56→
57→  const { data: { user } } = await supabase.auth.getUser()
58→
59→  // Protect /app routes
60→  if (request.nextUrl.pathname.startsWith('/app') && !user) {
61→    return NextResponse.redirect(new URL('/login', request.url))
62→  }
63→
64→  // Redirect logged in users away from auth pages
65→  if ((request.nextUrl.pathname === '/login' || request.nextUrl.pathname === '/register') && user) {
66→    return NextResponse.redirect(new URL('/app', request.url))
67→  }
68→
69→  return response
70→}

 1→import { createServerClient, type CookieOptions } from '@supabase/ssr'
 2→import { cookies } from 'next/headers'
 3→
 4→export function createClient() {
 5→  const cookieStore = cookies()
 6→
 7→  return createServerClient(
 8→    process.env.NEXT_PUBLIC_SUPABASE_URL!,
 9→    process.env.NEXT_PUBLIC_SUPABASE_ANON_KEY!,
10→    {
11→      cookies: {
12→        get(name: string) {
13→          return cookieStore.get(name)?.value
14→        },
15→        set(name: string, value: string, options: CookieOptions) {
16→          try {
17→            cookieStore.set({ name, value, ...options })
18→          } catch (error) {
19→            // The `set` method was called from a Server Component.
20→            // This can be ignored if you have middleware refreshing
21→            // user sessions.
22→          }
23→        },
24→        remove(name: string, options: CookieOptions) {
25→          try {
26→            cookieStore.set({ name, value: '', ...options })
27→          } catch (error) {
28→            // The `delete` method was called from a Server Component.
29→          }
30→        },
31→      },
32→    }
33→  )
34→}

 1→import Stripe from 'stripe';
 2→
 3→// Lazy initialization to avoid build-time env var errors
 4→let _stripe: Stripe | null = null;
 5→export const getStripe = () => {
 6→  if (!_stripe) {
 7→    _stripe = new Stripe(process.env.STRIPE_SECRET_KEY!, {
 8→      apiVersion: '2024-04-10',
 9→      typescript: true,
10→    });
11→  }
12→  return _stripe;
13→};
14→
15→// Keep backward-compatible export (getter pattern)
16→export const stripe = new Proxy({} as Stripe, {
17→  get(_, prop) {
18→    return (getStripe() as any)[prop];
19→  },
20→});
21→
22→export const PLANS = {
23→  starter: process.env.STRIPE_PRICE_STARTER || 'price_starter_monthly', // TODO: Set STRIPE_PRICE_STARTER in env
24→  pro: process.env.STRIPE_PRICE_PRO || 'price_pro_monthly',             // TODO: Set STRIPE_PRICE_PRO in env
25→  agency: process.env.STRIPE_PRICE_AGENCY || 'price_agency_monthly',   // TODO: Set STRIPE_PRICE_AGENCY in env
26→};
27→
28→export function getPlanFromPriceId(priceId: string): 'starter' | 'pro' | 'agency' {
29→  if (priceId === PLANS.agency) return 'agency';
30→  if (priceId === PLANS.pro) return 'pro';
31→  return 'starter';
32→}

