 25→const normalizeHeat = (score: number): Heat => {
 26→  if (score >= 90) {
 27→    return 'burning';
 28→  }
 29→  if (score >= 75) {
 30→    return 'hot';
 31→  }
 32→  if (score >= 50) {
 33→    return 'warm';
 34→  }
 35→  return 'cold';
 36→};
