 38→const parseGeminiText = (raw: string): GeminiAnalysis => {
 39→  const cleaned = raw.trim().replace(/^```json\s*/i, '').replace(/^```/i, '').replace(/```$/i, '').trim();
 40→  return JSON.parse(cleaned) as GeminiAnalysis;
 41→};
