161→Deno.serve(async (request: Request) => {
162→  if (request.method === 'OPTIONS') {
163→    return new Response('ok', { headers: corsHeaders });
164→  }
165→
166→  const ip = request.headers.get('x-forwarded-for') ?? 'anonymous';
167→  try {
168→    enforceRateLimit(`analyze:${ip}`, 100);
169→    if (request.method !== 'POST') {
170→      return jsonResponse({ error: 'Method not allowed' }, 405);
171→    }
172→
173→    const payload = await parseJsonBody<AnalyzePayload>(request);
174→    if (!payload.sector || !payload.source || !payload.raw_data) {
175→      return jsonResponse({ error: 'Payload invalide' }, 400);
176→    }
177→
178→    const geminiApiKey = Deno.env.get('GEMINI_API_KEY');
179→    const supabaseUrl = Deno.env.get('SUPABASE_URL');
180→    const serviceRoleKey = Deno.env.get('SUPABASE_SERVICE_ROLE_KEY');
181→    if (!geminiApiKey || !supabaseUrl || !serviceRoleKey) {
182→      throw new Error('Variables GEMINI_API_KEY / SUPABASE manquantes');
183→    }
184→
185→    const marketContext = {
186→      timestamp: new Date().toISOString(),
187→      source: payload.source,
188→      sector: payload.sector,
189→    };
190→
191→    const prompt = buildPrompt(payload.sector, payload.raw_data, marketContext, payload.approach_tone ?? 'professional');
192→    let analysis = await callGemini('gemini-1.5-flash', prompt, geminiApiKey);
193→    analysis.score = Math.max(0, Math.min(100, Number(analysis.score ?? 0)));
194→    analysis.heat = normalizeHeat(analysis.score);
195→
196→    if (!payload.message_only && analysis.score >= 90) {
197→      const refined = await callGemini('gemini-1.5-pro', prompt, geminiApiKey);
198→      refined.score = Math.max(0, Math.min(100, Number(refined.score ?? analysis.score)));
199→      refined.heat = normalizeHeat(refined.score);
200→      analysis = refined;
201→    }
202→
203→    if (payload.message_only) {
204→      return jsonResponse({
205→        approach_message: analysis.approach_message,
206→        heat: analysis.heat,
207→        score: analysis.score,
208→      });
209→    }
210→
211→    const admin = createAdminClient();
212→    const dedupHash =
213→      payload.dedup_hash ??
214→      (await sha256Hex(
215→        [
216→          String(payload.raw_data.name ?? payload.raw_data.title ?? ''),
217→          String(payload.raw_data.location ?? payload.raw_data.city ?? ''),
218→          String(payload.raw_data.date ?? payload.raw_data.created_at ?? ''),
219→          payload.source,
220→          payload.sector,
221→        ]
222→          .map((value) => value.trim().toLowerCase())
223→          .join('|'),
224→      ));
225→
226→    const signal = String(analysis.signal ?? '').slice(0, 100);
227→    const sourceUrl = String(payload.raw_data.source_url ?? payload.raw_data.url ?? '');
228→    const location = String(payload.raw_data.location ?? payload.raw_data.city ?? '');
229→
230→    const { data: inserted, error: insertError } = await admin
231→      .from('prospects')
232→      .insert({
233→        sector_id: payload.sector,
234→        source_id: payload.source_id ?? null,
235→        score: analysis.score,
236→        heat: analysis.heat,
237→        signal,
238→        signal_type: String(payload.raw_data.signal_type ?? ''),
239→        name: String(payload.raw_data.name ?? payload.raw_data.title ?? 'Prospect detecte'),
240→        location: location || null,
241→        location_lat: typeof payload.raw_data.location_lat === 'number' ? payload.raw_data.location_lat : null,
242→        location_lng: typeof payload.raw_data.location_lng === 'number' ? payload.raw_data.location_lng : null,
243→        contact_phone: payload.raw_data.contact_phone ? String(payload.raw_data.contact_phone) : null,
244→        contact_email: payload.raw_data.contact_email ? String(payload.raw_data.contact_email) : null,
245→        contact_method: payload.raw_data.contact_method ? String(payload.raw_data.contact_method) : null,
246→        details_json: payload.raw_data.details && typeof payload.raw_data.details === 'object' ? payload.raw_data.details : payload.raw_data,
247→        market_analysis_json: analysis.market_analysis ?? {},
248→        approach_message: analysis.approach_message,
249→        approach_why: analysis.approach_why,
250→        score_breakdown_json: analysis.score_breakdown ?? {},
251→        raw_data_json: payload.raw_data,
252→        source_url: sourceUrl || null,
253→        dedup_hash: dedupHash,
254→      })
255→      .select('id, heat, score')
256→      .single<{ id: string; heat: Heat; score: number }>();
257→
258→    if (insertError) {
259→      throw insertError;
260→    }
261→
262→    await logAutomationEvent('prospect_scored', {
263→      prospect_id: inserted.id,
264→      sector: payload.sector,
265→      score: inserted.score,
266→      heat: inserted.heat,
267→    }, payload.source_id ?? null);
268→
269→    const controller = new AbortController();
270→    const timeoutId = setTimeout(() => controller.abort(), 30_000);
271→    const distributeResponse = await fetch(`${supabaseUrl}/functions/v1/distribute`, {
272→      method: 'POST',
273→      signal: controller.signal,
274→      headers: {
275→        Authorization: `Bearer ${serviceRoleKey}`,
276→        apikey: serviceRoleKey,
277→        'Content-Type': 'application/json',
278→      },
279→      body: JSON.stringify({
280→        prospect_id: inserted.id,
281→      }),
282→    });
283→    clearTimeout(timeoutId);
284→
285→    if (!distributeResponse.ok) {
286→      const details = await distributeResponse.text();
287→      await logAutomationEvent('error', {
288→        stage: 'analyze->distribute',
289→        prospect_id: inserted.id,
290→        reason: details,
291→      }, payload.source_id ?? null);
292→    }
293→
294→    return jsonResponse({
295→      prospect_id: inserted.id,
296→      score: inserted.score,
297→      heat: inserted.heat,
298→    });
299→  } catch (error) {
300→    await logAutomationEvent('error', {
301→      stage: 'analyze',
302→      reason: error instanceof Error ? error.message : 'unknown',
303→    });
304→    return jsonResponse({ error: error instanceof Error ? error.message : 'Erreur analyze' }, 500);
305→  }
306→});
