 82→const resolvePaymentMethodId = async (customerId: string): Promise<string | null> => {
 83→  const customer = await stripe.customers.retrieve(customerId);
 84→  if ('deleted' in customer && customer.deleted) {
 85→    return null;
 86→  }
 87→  const defaultPm = customer.invoice_settings?.default_payment_method;
 88→  if (typeof defaultPm === 'string' && defaultPm) {
 89→    return defaultPm;
 90→  }
 91→  const listed = await stripe.paymentMethods.list({
 92→    customer: customerId,
 93→    type: 'card',
 94→    limit: 1,
 95→  });
 96→  const fallback = listed.data[0]?.id ?? null;
 97→  if (fallback) {
 98→    await stripe.customers.update(customerId, {
 99→      invoice_settings: {
100→        default_payment_method: fallback,
101→      },
102→    });
103→  }
104→  return fallback;
105→};
