110→Deno.serve(async (request: Request) => {
111→  if (request.method === 'OPTIONS') {
112→    return new Response('ok', { headers: corsHeaders });
113→  }
114→
115→  const ip = request.headers.get('x-forwarded-for') ?? 'anonymous';
116→  let userIdForLog: string | null = null;
117→
118→  try {
119→    enforceRateLimit(`auto-recharge:${ip}`, 100);
120→    if (request.method !== 'POST') {
121→      return jsonResponse({ error: 'Method not allowed' }, 405);
122→    }
123→
124→    const payload = await parseJsonBody<AutoRechargePayload>(request);
125→    if (!payload.user_id) {
126→      return jsonResponse({ error: 'user_id requis' }, 400);
127→    }
128→    userIdForLog = payload.user_id;
129→
130→    const admin = createAdminClient();
131→    const { data: profile, error: profileError } = await admin
132→      .from('profiles')
133→      .select(
134→        'id, stripe_customer_id, credits_balance, credits_total_purchased, auto_recharge_enabled, auto_recharge_pack_id, auto_recharge_trigger_threshold, auto_recharge_max_per_month, auto_recharge_count_month, auto_recharge_month_ref',
135→      )
136→      .eq('id', payload.user_id)
137→      .single<ProfileAutoRechargeRow>();
138→    if (profileError || !profile) {
139→      throw new Error('Profil introuvable');
140→    }
141→
142→    if (!profile.auto_recharge_enabled) {
143→      return jsonResponse({
144→        recharged: false,
145→        reason: 'auto_recharge_disabled',
146→        credits_balance: profile.credits_balance,
147→      });
148→    }
149→
150→    const required = Math.max(1, Number(payload.minimum_required_credits ?? profile.auto_recharge_trigger_threshold));
151→    if (profile.credits_balance >= required) {
152→      return jsonResponse({
153→        recharged: false,
154→        reason: 'enough_balance',
155→        credits_balance: profile.credits_balance,
156→      });
157→    }
158→
159→    if (!profile.stripe_customer_id) {
160→      throw new Error('Aucun customer Stripe configure pour auto-recharge');
161→    }
162→
163→    const packId = profile.auto_recharge_pack_id ?? 'pack_50';
164→    const pack = getPackConfigs().find((item) => item.id === packId);
165→    if (!pack || !pack.priceId) {
166→      throw new Error('Pack auto-recharge non configure cote Stripe');
167→    }
168→
169→    const currentMonth = monthStartIso();
170→    const storedMonth = normalizeMonthRef(profile.auto_recharge_month_ref);
171→    let monthlyCount = profile.auto_recharge_count_month;
172→    if (storedMonth !== currentMonth) {
173→      monthlyCount = 0;
174→      await admin
175→        .from('profiles')
176→        .update({
177→          auto_recharge_count_month: 0,
178→          auto_recharge_month_ref: currentMonth,
179→        })
180→        .eq('id', profile.id);
181→    }
182→
183→    if (monthlyCount >= profile.auto_recharge_max_per_month) {
