151→/**
152→ * Distribution user-level d'un prospect nouvellement analyse.
153→ * Chaque assignment consomme des credits prepaid.
154→ */
155→Deno.serve(async (request: Request) => {
156→  if (request.method === 'OPTIONS') {
157→    return new Response('ok', { headers: corsHeaders });
158→  }
159→
160→  const ip = request.headers.get('x-forwarded-for') ?? 'anonymous';
161→  try {
162→    enforceRateLimit(`distribute:${ip}`, 100);
163→    if (request.method !== 'POST') {
164→      return jsonResponse({ error: 'Method not allowed' }, 405);
165→    }
166→    const payload = await parseJsonBody<DistributePayload>(request);
167→    if (!payload.prospect_id) {
168→      return jsonResponse({ error: 'prospect_id requis' }, 400);
169→    }
170→
171→    const admin = createAdminClient();
172→    const { data: prospect, error: prospectError } = await admin
173→      .from('prospects')
174→      .select('id, sector_id, score, heat, signal, name, location, contact_email, approach_message, location_lat, location_lng')
175→      .eq('id', payload.prospect_id)
176→      .single<ProspectRow>();
177→    if (prospectError || !prospect) {
178→      throw new Error('Prospect introuvable');
179→    }
180→    const safeSectorFilterValue = prospect.sector_id.replaceAll(',', '').replaceAll('{', '').replaceAll('}', '');
181→
182→    const { data: profiles, error: profilesError } = await admin
183→      .from('profiles')
184→      .select(
185→        'id, full_name, sector_id, target_sector_ids, min_score, location_lat, location_lng, geo_radius_km, credits_balance, credits_total_spent, credit_cost_per_prospect, low_credit_threshold, burning_only_alerts, auto_recharge_enabled, auto_recharge_trigger_threshold, automation_enabled, automation_send_email, automation_min_score, automation_daily_email_limit, automation_emails_sent_today, automation_email_day, automation_email_subject_template, automation_email_signature',
186→      )
187→      .or(`sector_id.eq.${safeSectorFilterValue},target_sector_ids.cs.{${safeSectorFilterValue}}`);
188→    if (profilesError) {
189→      throw profilesError;
190→    }
191→
192→    const supabaseUrl = Deno.env.get('SUPABASE_URL');
193→    const serviceRoleKey = Deno.env.get('SUPABASE_SERVICE_ROLE_KEY');
194→    if (!supabaseUrl || !serviceRoleKey) {
195→      throw new Error('Variables Supabase manquantes');
196→    }
197→
198→    let assigned = 0;
199→    let skipped = 0;
200→    let creditWarnings = 0;
201→    let autoRecharged = 0;
202→    let autoEmailsSent = 0;
203→    const nowIso = new Date().toISOString();
204→    const today = currentUtcDate();
205→
206→    for (const profile of (profiles ?? []) as ProfileRow[]) {
207→      const targetSectorIds = Array.isArray(profile.target_sector_ids) ? profile.target_sector_ids : [];
208→      const sectorMatch =
209→        targetSectorIds.length > 0 ? targetSectorIds.includes(prospect.sector_id) : profile.sector_id === prospect.sector_id;
210→      if (!sectorMatch) {
211→        skipped += 1;
212→        continue;
213→      }
214→
215→      if (prospect.score < profile.min_score) {
216→        skipped += 1;
217→        continue;
218→      }
219→
220→      if (
221→        profile.location_lat !== null &&
222→        profile.location_lng !== null &&
223→        prospect.location_lat !== null &&
224→        prospect.location_lng !== null
225→      ) {
226→        const distance = haversineKm(profile.location_lat, profile.location_lng, prospect.location_lat, prospect.location_lng);
227→        if (distance > profile.geo_radius_km) {
228→          skipped += 1;
229→          continue;
230→        }
231→      }
232→
233→      const creditCost = Math.max(1, profile.credit_cost_per_prospect || 1);
234→      let currentBalance = profile.credits_balance;
235→
236→      if (currentBalance < creditCost && profile.auto_recharge_enabled) {
237→        const rechargeResponse = await attemptAutoRecharge(
238→          supabaseUrl,
239→          serviceRoleKey,
240→          profile.id,
241→          Math.max(creditCost, profile.auto_recharge_trigger_threshold),
242→        );
243→        if (rechargeResponse.recharged && typeof rechargeResponse.credits_balance === 'number') {
244→          currentBalance = rechargeResponse.credits_balance;
245→          autoRecharged += 1;
246→        } else if (rechargeResponse.error) {
247→          await logAutomationEvent('error', {
248→            stage: 'distribute-auto-recharge',
249→            user_id: profile.id,
250→            reason: rechargeResponse.error,
251→          });
252→        }
253→      }
254→
255→      if (currentBalance < creditCost) {
256→        creditWarnings += 1;
257→        await fetch(`${supabaseUrl}/functions/v1/notify`, {
258→          method: 'POST',
259→          headers: {
260→            Authorization: `Bearer ${serviceRoleKey}`,
261→            apikey: serviceRoleKey,
262→            'Content-Type': 'application/json',
263→          },
264→          body: JSON.stringify({
265→            user_id: profile.id,
266→            prospect_id: null,
267→            type: 'credit_warning',
268→          }),
269→        });
270→        continue;
271→      }
272→
273→      const { data: insertedAssignment, error: assignmentError } = await admin
274→        .from('prospect_assignments')
275→        .insert({
276→          prospect_id: prospect.id,
277→          user_id: profile.id,
278→          status: 'new',
279→          created_at: nowIso,
280→          updated_at: nowIso,
281→        })
282→        .select('id')
283→        .maybeSingle<{ id: string }>();
284→
285→      if (assignmentError) {
286→        if (!assignmentError.message.toLowerCase().includes('duplicate')) {
287→          await logAutomationEvent('error', {
288→            stage: 'distribute-assignment',
289→            user_id: profile.id,
290→            reason: assignmentError.message,
291→          });
292→        }
293→        continue;
294→      }
295→
296→      if (!insertedAssignment?.id) {
297→        continue;
298→      }
299→
300→      assigned += 1;
301→      const nextBalance = Math.max(0, currentBalance - creditCost);
302→      const nextSpent = profile.credits_total_spent + creditCost;
303→
304→      let nextAutomationDay = profile.automation_email_day ?? today;
305→      let nextAutomationCount = profile.automation_emails_sent_today;
306→      if (nextAutomationDay !== today) {
307→        nextAutomationDay = today;
308→        nextAutomationCount = 0;
309→      }
310→
311→      let emailSent = false;
312→      const canAutoEmail =
313→        profile.automation_enabled &&
314→        profile.automation_send_email &&
315→        Boolean(prospect.contact_email) &&
316→        prospect.score >= profile.automation_min_score &&
317→        nextAutomationCount < profile.automation_daily_email_limit;
318→
319→      if (canAutoEmail) {
320→        emailSent = await sendAutomatedProspectEmail(profile, prospect);
321→        if (emailSent) {
322→          nextAutomationCount += 1;
323→          autoEmailsSent += 1;
324→          await logAutomationEvent('notification_sent', {
325→            stage: 'automation_email',
326→            user_id: profile.id,
327→            prospect_id: prospect.id,
328→            assignment_id: insertedAssignment.id,
329→            to: prospect.contact_email,
330→          });
331→
332→          await admin
333→            .from('prospect_assignments')
334→            .update({
335→              status: 'contacted',
336→              contacted_at: nowIso,
337→              updated_at: nowIso,
338→            })
339→            .eq('id', insertedAssignment.id);
340→        }
341→      }
342→
343→      const { error: debitError } = await admin
344→        .from('profiles')
345→        .update({
346→          credits_balance: nextBalance,
347→          credits_total_spent: nextSpent,
348→          automation_email_day: nextAutomationDay,
349→          automation_emails_sent_today: nextAutomationCount,
350→          updated_at: nowIso,
351→        })
352→        .eq('id', profile.id);
353→
354→      if (debitError) {
355→        await logAutomationEvent('error', {
356→          stage: 'distribute-debit',
357→          user_id: profile.id,
358→          reason: debitError.message,
359→        });
360→      } else {
361→        await admin.from('credit_transactions').insert({
362→          user_id: profile.id,
363→          transaction_type: 'consume',
364→          credits_delta: -creditCost,
365→          credits_balance_after: nextBalance,
366→          description: `Generation fiche prospect ${prospect.id}`,
367→          metadata_json: {
368→            prospect_id: prospect.id,
369→            assignment_id: insertedAssignment.id,
370→          },
371→        });
372→      }
373→
374→      const notificationType = prospect.heat === 'burning' ? 'burning_alert' : 'new_prospect';
375→      const shouldNotifyNow = prospect.heat === 'burning' || !profile.burning_only_alerts;
376→      if (shouldNotifyNow) {
377→        await fetch(`${supabaseUrl}/functions/v1/notify`, {
378→          method: 'POST',
379→          headers: {
380→            Authorization: `Bearer ${serviceRoleKey}`,
381→            apikey: serviceRoleKey,
382→            'Content-Type': 'application/json',
383→          },
384→          body: JSON.stringify({
385→            user_id: profile.id,
386→            prospect_id: prospect.id,
387→            type: notificationType,
388→          }),
389→        });
390→      }
391→
392→      if (nextBalance <= profile.low_credit_threshold) {
393→        creditWarnings += 1;
394→        await fetch(`${supabaseUrl}/functions/v1/notify`, {
395→          method: 'POST',
396→          headers: {
397→            Authorization: `Bearer ${serviceRoleKey}`,
398→            apikey: serviceRoleKey,
399→            'Content-Type': 'application/json',
400→          },
401→          body: JSON.stringify({
402→            user_id: profile.id,
403→            prospect_id: prospect.id,
404→            type: 'credit_warning',
405→          }),
406→        });
407→      }
408→    }
409→
410→    await logAutomationEvent('scan_completed', {
411→      stage: 'distribution',
412→      prospect_id: prospect.id,
413→      assigned,
414→      skipped,
415→      credit_warnings: creditWarnings,
416→      auto_recharged: autoRecharged,
417→      automation_emails_sent: autoEmailsSent,
418→    });
419→
420→    return jsonResponse({
421→      prospect_id: prospect.id,
422→      assigned,
423→      skipped,
424→      credit_warnings: creditWarnings,
425→      auto_recharged: autoRecharged,
426→      automation_emails_sent: autoEmailsSent,
427→    });
428→  } catch (error) {
429→    await logAutomationEvent('error', {
430→      stage: 'distribute',
431→      reason: error instanceof Error ? error.message : 'unknown',
432→    });
433→    return jsonResponse({ error: error instanceof Error ? error.message : 'Erreur distribute' }, 500);
434→  }
435→});
