 43→const toStringArray = (value: unknown): string[] => {
 44→  if (!Array.isArray(value)) {
 45→    return [];
 46→  }
 47→  return value
 48→    .map((item) => String(item ?? '').trim())
 49→    .filter((item) => Boolean(item));
 50→};
 51→
 52→const unique = (values: string[]): string[] => [...new Set(values)];
 53→
 54→const getEffectiveSectorIds = (profile: ProfileRow): string[] => {
 55→  const fromTargets = toStringArray(profile.target_sector_ids);
 56→  if (fromTargets.length > 0) {
 57→    return unique(fromTargets);
 58→  }
 59→  if (profile.sector_id?.trim()) {
 60→    return [profile.sector_id.trim()];
 61→  }
 62→  return [];
 63→};
