 65→const isSourceEnabledForUser = (sourcesConfig: Record<string, boolean> | null, sourceId: string): boolean => {
 66→  if (!sourcesConfig || typeof sourcesConfig !== 'object') {
 67→    return true;
 68→  }
 69→  const raw = sourcesConfig[sourceId];
 70→  if (typeof raw === 'boolean') {
 71→    return raw;
 72→  }
 73→  return true;
 74→};
 75→
 76→const getBearerToken = (request: Request): string | null => {
 77→  const authorizationHeader = request.headers.get('authorization');
 78→  if (!authorizationHeader) {
 79→    return null;
 80→  }
 81→  if (!authorizationHeader.toLowerCase().startsWith('bearer ')) {
 82→    return null;
 83→  }
 84→  return authorizationHeader.slice(7).trim() || null;
 85→};
