204→/**
205→ * Lance un scan manuel immediat pour les secteurs/sources cibles de l'utilisateur.
206→ */
207→Deno.serve(async (request: Request) => {
208→  if (request.method === 'OPTIONS') {
209→    return new Response('ok', { headers: corsHeaders });
210→  }
211→
212→  const ip = request.headers.get('x-forwarded-for') ?? 'anonymous';
213→  try {
214→    enforceRateLimit(`scan-now:${ip}`, 100);
215→    if (request.method !== 'POST') {
216→      return jsonResponse({ error: 'Method not allowed' }, 405);
217→    }
218→
219→    let payload: ScanNowPayload = {};
220→    try {
221→      payload = await parseJsonBody<ScanNowPayload>(request);
222→    } catch {
223→      payload = {};
224→    }
225→
226→    const admin = createAdminClient();
227→    const token = getBearerToken(request);
228→    let tokenUserId: string | null = null;
229→    if (token) {
230→      const { data: userData, error: userError } = await admin.auth.getUser(token);
231→      if (userError) {
232→        return jsonResponse({ error: 'Session invalide' }, 401);
233→      }
234→      tokenUserId = userData.user?.id ?? null;
235→    }
236→
237→    const requestedUserId = String(payload.user_id ?? tokenUserId ?? '').trim();
238→    if (!requestedUserId) {
239→      return jsonResponse({ error: 'user_id requis' }, 400);
240→    }
241→    if (tokenUserId && tokenUserId !== requestedUserId) {
242→      return jsonResponse({ error: 'Action interdite' }, 403);
243→    }
244→
245→    const { data: profile, error: profileError } = await admin
246→      .from('profiles')
247→      .select('id, sector_id, target_sector_ids, location_label, min_score, scan_frequency_hours, sources_config')
248→      .eq('id', requestedUserId)
249→      .single<ProfileRow>();
250→    if (profileError || !profile) {
251→      return jsonResponse({ error: 'Profil introuvable' }, 404);
252→    }
253→
254→    const sectorIds = getEffectiveSectorIds(profile);
255→    if (sectorIds.length === 0) {
256→      return jsonResponse({ error: 'Aucun secteur cible configure' }, 400);
257→    }
258→
259→    const sourceIdFilter = toStringArray(payload.source_ids);
260→    const sourceQuery = admin
261→      .from('sources')
262→      .select('id, sector_id, name, type, data_type, config_json, is_active')
263→      .in('sector_id', sectorIds)
264→      .eq('is_active', true)
265→      .order('created_at', { ascending: true });
266→
267→    const { data: sourceRows, error: sourceError } =
268→      sourceIdFilter.length > 0 ? await sourceQuery.in('id', sourceIdFilter) : await sourceQuery;
269→
270→    if (sourceError) {
271→      throw sourceError;
272→    }
273→
274→    const selectedSources = ((sourceRows ?? []) as SourceRow[]).filter((source) =>
275→      isSourceEnabledForUser(profile.sources_config, source.id),
276→    );
277→
278→    if (selectedSources.length === 0) {
279→      return jsonResponse({ error: 'Aucune source active pour ce ciblage' }, 400);
280→    }
281→
282→    const maxSources = Math.max(1, Math.min(30, Number(payload.max_sources ?? 12)));
283→    const sourcesToRun = selectedSources.slice(0, maxSources);
284→
285→    const n8nWebhookUrl = Deno.env.get('N8N_WEBHOOK_URL');
286→    const n8nWebhookToken = Deno.env.get('N8N_WEBHOOK_TOKEN') ?? null;
287→    const supabaseUrl = Deno.env.get('SUPABASE_URL');
288→    const serviceRoleKey = Deno.env.get('SUPABASE_SERVICE_ROLE_KEY');
289→
290→    if (!supabaseUrl || !serviceRoleKey) {
291→      throw new Error('Variables Supabase manquantes');
292→    }
293→
294→    const jobId = crypto.randomUUID();
295→    const startedAt = new Date().toISOString();
296→    await logAutomationEvent('scan_started', {
297→      stage: 'scan_now',
298→      job_id: jobId,
299→      user_id: profile.id,
300→      sector_ids: sectorIds,
301→      source_ids: sourcesToRun.map((source) => source.id),
302→    });
303→
304→    let triggeredSources = 0;
305→    let failedSources = 0;
306→    let fallbackDirectCount = 0;
307→    const triggeredSourceIds: string[] = [];
308→    const sourceResults: Array<Record<string, unknown>> = [];
309→
310→    for (let index = 0; index < sourcesToRun.length; index += 1) {
311→      const source = sourcesToRun[index];
312→      let runOk = false;
313→
314→      if (n8nWebhookUrl) {
315→        const n8nResult = await triggerN8nManualScan(n8nWebhookUrl, n8nWebhookToken, {
316→          mode: 'manual_scan',
317→          job_id: jobId,
318→          requested_at: startedAt,
319→          user_id: profile.id,
320→          source_id: source.id,
321→          source_name: source.name,
322→          sector: source.sector_id,
323→          location_label: profile.location_label,
324→          min_score: profile.min_score,
325→          scan_frequency_hours: profile.scan_frequency_hours,
326→        });
327→
328→        if (n8nResult.ok) {
329→          runOk = true;
330→          triggeredSources += 1;
331→          triggeredSourceIds.push(source.id);
332→          sourceResults.push({
333→            source_id: source.id,
334→            source_name: source.name,
335→            mode: 'n8n',
336→            status: n8nResult.status,
337→          });
338→        }
339→      }
340→
341→      if (!runOk) {
342→        const syntheticItem = buildSyntheticLeadItem(source, profile, jobId, index);
343→        const directResult = await triggerDirectIngest(supabaseUrl, serviceRoleKey, source, syntheticItem);
344→        if (directResult.ok) {
345→          runOk = true;
346→          triggeredSources += 1;
347→          fallbackDirectCount += 1;
348→          triggeredSourceIds.push(source.id);
349→          sourceResults.push({
350→            source_id: source.id,
351→            source_name: source.name,
352→            mode: 'direct_ingest',
353→            status: directResult.status,
354→            ingested: directResult.data?.ingested ?? null,
355→            duplicates: directResult.data?.duplicates ?? null,
356→            errors: directResult.data?.errors ?? null,
357→          });
358→        } else {
359→          failedSources += 1;
360→          sourceResults.push({
361→            source_id: source.id,
362→            source_name: source.name,
363→            mode: 'direct_ingest',
364→            status: directResult.status,
365→            error: directResult.data?.error ?? directResult.body,
366→          });
367→        }
368→      }
369→    }
370→
371→    if (triggeredSourceIds.length > 0) {
372→      await admin
373→        .from('sources')
374→        .update({
375→          last_scan_at: startedAt,
376→        })
377→        .in('id', triggeredSourceIds);
378→    }
379→
380→    await logAutomationEvent('scan_completed', {
381→      stage: 'scan_now',
382→      job_id: jobId,
383→      user_id: profile.id,
384→      triggered_sources: triggeredSources,
385→      failed_sources: failedSources,
386→      fallback_direct_ingest: fallbackDirectCount,
387→      source_results: sourceResults,
388→    });
389→
390→    return jsonResponse({
391→      job_id: jobId,
392→      started_at: startedAt,
393→      sectors_count: sectorIds.length,
394→      selected_sources: sourcesToRun.length,
395→      triggered_sources: triggeredSources,
396→      failed_sources: failedSources,
397→      fallback_direct_ingest: fallbackDirectCount,
398→      used_n8n: Boolean(n8nWebhookUrl),
399→      source_results: sourceResults,
400→    });
401→  } catch (error) {
402→    await logAutomationEvent('error', {
403→      stage: 'scan_now',
404→      reason: error instanceof Error ? error.message : 'unknown',
405→    });
406→    return jsonResponse({ error: error instanceof Error ? error.message : 'Erreur scan-now' }, 500);
407→  }
408→});
